     1	//! This test creates snapshots of the reports of all linters.
     2	//!
     3	//! # Usage
     4	//!
     5	//! To add a new snapshot, simply add the document to `tests/text` and run this
     6	//! test. It will automatically create a new snapshot in `tests/text/linters`.
     7	//! To update an existing snapshot, also just run this test.
     8	//!
     9	//! Note: This test will fail if the snapshot files are not up to date. This
    10	//! ensures that CI will fail if linters change their behavior.
    11	
    12	use harper_core::spell::FstDictionary;
    13	use harper_core::{
    14	    Dialect, Document,
    15	    linting::{LintGroup, Linter},
    16	};
