    18	mod snapshot;
    19	
    20	struct LinePos {
    21	    /// 0-based index of the line
    22	    pub line: usize,
    23	    /// 0-based index of the column
    24	    pub col: usize,
    25	}
    26	
    27	struct Lines<'a> {
    28	    lines: Vec<&'a str>,
    29	    offsets: Vec<usize>,
    30	}
    31	impl Lines<'_> {
    32	    fn new(source: &'_ str) -> Lines<'_> {
    33	        let lines: Vec<&str> = source.split('\n').collect();
    34	        let offsets: Vec<usize> = lines
    35	            .iter()
    36	            .scan(0, |offset, line| {
    37	                let old_offset = *offset;
    38	                *offset += line.chars().count() + 1;
    39	                Some(old_offset)
    40	            })
    41	            .collect();
    42	
    43	        Lines { lines, offsets }
    44	    }
    45	
    46	    fn len(&self) -> usize {
    47	        self.lines.len()
    48	    }
    49	
    50	    fn get_pos(&self, offset: usize) -> LinePos {
    51	        let line_index = self
    52	            .offsets
    53	            .binary_search(&offset)
    54	            .unwrap_or_else(|x| x - 1);
    55	
    56	        LinePos {
    57	            line: line_index,
    58	            col: offset - self.offsets[line_index],
    59	        }
    60	    }
    61	}
    62	impl<'a> std::ops::Index<usize> for Lines<'a> {
    63	    type Output = &'a str;
    64	
    65	    fn index(&self, index: usize) -> &Self::Output {
    66	        &self.lines[index]
    67	    }
    68	}
    69	
    70	fn print_error(lines: &Lines, start: usize, end: usize, message: &str) -> String {
    71	    let mut out = String::new();
    72	
    73	    fn print_line(out: &mut String, line: &str, number: usize) {
    74	        out.push_str(&format!("{number:>6} | {line}\n"));
    75	    }
    76	
    77	    fn is_sentence_boundary(c: char) -> bool {
    78	        matches!(c, '.' | '?' | '!' | ':' | ';')
    79	    }
    80	    fn print_pre_line_context(
    81	        out: &mut String,
    82	        context_line: &str,
    83	        number: usize,
    84	        line: &str,
    85	        start_col: usize,
    86	    ) {
    87	        if context_line.is_empty() {
    88	            return;
    89	        }
    90	        if start_col > 40 {
    91	            // that's enough context
    92	            return;
    93	        }
    94	
    95	        let last_char = context_line.chars().last().unwrap();
    96	        let mut chars_before = line.chars().take(start_col);
    97	        if !is_sentence_boundary(last_char) && !chars_before.any(is_sentence_boundary) {
    98	            print_line(out, context_line, number);
    99	        }
   100	    }
   101	    fn print_post_line_context(
   102	        out: &mut String,
   103	        context_line: &str,
   104	        number: usize,
   105	        line: &str,
   106	        end_col: usize,
   107	    ) {
   108	        if context_line.is_empty() {
   109	            return;
   110	        }
   111	        if end_col < 40 {
   112	            // that's enough context
   113	            return;
   114	        }
   115	
   116	        let mut chars_after = line.chars().skip(end_col);
   117	        if !chars_after.any(is_sentence_boundary) {
   118	            print_line(out, context_line, number);
   119	        }
   120	    }
   121	
   122	    fn print_underline(
   123	        out: &mut String,
   124	        start_col: usize,
   125	        end_col: usize,
   126	        continuation: bool,
   127	        message: &str,
   128	    ) {
   129	        out.push_str("       | ");
   130	        for _ in 0..start_col {
   131	            out.push(' ');
   132	        }
   133	        out.push(if continuation { '~' } else { '^' });
   134	        for _ in 0..end_col.saturating_sub(start_col) {
   135	            out.push('~');
   136	        }
   137	
   138	        if !message.is_empty() {
   139	            out.push(' ');
   140	            out.push_str(message);
   141	        }
   142	        out.push('\n');
   143	    }
   144	
   145	    let start = lines.get_pos(start);
   146	    let end = lines.get_pos(end - 1);
   147	
   148	    if start.line > 0 {
   149	        print_pre_line_context(
   150	            &mut out,
   151	            lines[start.line - 1],
   152	            start.line,
   153	            lines[start.line],
   154	            start.col,
   155	        );
   156	    }
   157	
   158	    if start.line == end.line {
   159	        print_line(&mut out, lines[start.line], start.line + 1);
   160	        print_underline(&mut out, start.col, end.col, false, message);
   161	    } else {
   162	        for i in start.line..end.line {
   163	            let line = lines[i];
   164	            print_line(&mut out, line, i + 1);
   165	            print_underline(
   166	                &mut out,
   167	                if i == start.line { start.col } else { 0 },
   168	                line.chars().count(),
   169	                i != start.line,
   170	                "",
   171	            );
   172	        }
   173	
   174	        print_line(&mut out, lines[end.line], end.line + 1);
   175	        print_underline(&mut out, 0, end.col, true, message);
   176	    }
   177	
   178	    if end.line + 1 < lines.len() {
   179	        print_post_line_context(
   180	            &mut out,
   181	            lines[end.line + 1],
   182	            end.line + 2,
   183	            lines[end.line],
   184	            end.col,
   185	        );
   186	    }
   187	
   188	    out
   189	}
