   191	#[test]
   192	fn test_most_lints() {
   193	    snapshot::snapshot_all_text_files("linters", ".snap.yml", |source, dialect_override| {
   194	        let dict = FstDictionary::curated();
   195	        let document = Document::new_markdown_default(source, &dict);
   196	
   197	        let mut linter = LintGroup::new_curated(
   198	            dict,
   199	            dialect_override.unwrap_or_else(|| {
   200	                Dialect::try_guess_from_document(&document).unwrap_or(Dialect::American)
   201	            }),
   202	        );
   203	
   204	        let mut lints = linter.lint(&document);
   205	        lints.sort_by(|a, b| {
   206	            a.span
   207	                .start
   208	                .cmp(&b.span.start)
   209	                .then(a.span.end.cmp(&b.span.end))
   210	        });
   211	
   212	        // split the input document into lines
   213	        let lines = Lines::new(source);
   214	
   215	        let mut out = String::new();
   216	
   217	        for lint in lints {
   218	            out.push_str(&format!(
   219	                "Lint:    {:?} ({} priority)\n",
   220	                lint.lint_kind, lint.priority
   221	            ));
   222	
   223	            let message = print_error(&lines, lint.span.start, lint.span.end, &lint.message);
   224	            out.push_str("Message: |\n");
   225	            for l in message.lines() {
   226	                out.push_str("  ");
   227	                out.push_str(l);
   228	                out.push('\n');
   229	            }
   230	
   231	            if !lint.suggestions.is_empty() {
   232	                out.push_str("Suggest:\n");
   233	                for suggestion in &lint.suggestions {
   234	                    out.push_str(&format!("  - {suggestion}\n"));
   235	                }
   236	            }
   237	
   238	            out.push_str("\n\n\n");
   239	        }
   240	
   241	        out
   242	    });
   243	}
