   239	    pub fn organized_lints(&mut self, document: &Document) -> BTreeMap<String, Vec<Lint>> {
   240	        let mut results = BTreeMap::new();
   241	
   242	        // Normal linters
   243	        for (key, linter) in &mut self.linters {
   244	            if self.config.is_rule_enabled(key) {
   245	                results.insert(key.clone(), linter.lint(document));
   246	            }
   247	        }
   248	
   249	        // Expr linters
   250	        for chunk in document.iter_chunks() {
   251	            let Some(chunk_span) = chunk.span() else {
   252	                continue;
   253	            };
   254	
   255	            let chunk_chars = document.get_span_content(&chunk_span);
   256	            let config_hash = self.hasher_builder.hash_one(&self.config);
   257	            let cache_key = (chunk_chars.into(), config_hash);
   258	
   259	            let mut chunk_results = if let Some(hit) = self.chunk_expr_cache.get(&cache_key) {
   260	                hit.clone()
   261	            } else {
   262	                let mut pattern_lints = BTreeMap::new();
   263	
   264	                for (key, linter) in &mut self.chunk_expr_linters {
   265	                    if self.config.is_rule_enabled(key) {
   266	                        let lints =
   267	                            run_on_chunk(linter, chunk, document.get_source()).map(|mut l| {
   268	                                l.span.pull_by(chunk_span.start);
   269	                                l
   270	                            });
   271	
   272	                        pattern_lints.insert(key.clone(), lints.collect());
   273	                    }
   274	                }
   275	
   276	                self.chunk_expr_cache.put(cache_key, pattern_lints.clone());
   277	                pattern_lints
   278	            };
   279	
   280	            // Bring the spans back into document-space
   281	            for value in chunk_results.values_mut() {
   282	                for lint in value {
   283	                    lint.span.push_by(chunk_span.start);
   284	                }
   285	            }
   286	
   287	            for (key, mut vec) in chunk_results {
   288	                results.entry(key).or_default().append(&mut vec);
   289	            }
   290	        }
   291	
   292	        results
   293	    }
   294	}
