   247	    /// Match a token where any of the token kind predicates returns true.
   248	    /// Like `then_kind_either` but for more than two predicates.
   249	    pub fn then_kind_any<F>(self, preds_is: &'static [F]) -> Self
   250	    where
   251	        F: Fn(&TokenKind) -> bool + Send + Sync + 'static,
   252	    {
   253	        self.then_kind_where(move |k| preds_is.iter().any(|pred| pred(k)))
