   258	    pub fn then_kind_none_of<F>(self, preds_isnt: &'static [F]) -> Self
   259	    where
   260	        F: Fn(&TokenKind) -> bool + Send + Sync + 'static,
   261	    {
   262	        self.then_kind_where(move |k| preds_isnt.iter().all(|pred| !pred(k)))
   263	    }
