   265	    /// Match a token where any of the token kind predicates returns true,
   266	    /// and the word is not in the list of exceptions.
   267	    pub fn then_kind_any_except<F>(
   268	        self,
   269	        preds_is: &'static [F],
   270	        ex: &'static [&'static str],
   271	    ) -> Self
   272	    where
   273	        F: Fn(&TokenKind) -> bool + Send + Sync + 'static,
   274	    {
   275	        self.then(move |tok: &Token, src: &[char]| {
   276	            preds_is.iter().any(|pred| pred(&tok.kind))
   277	                && !ex
   278	                    .iter()
   279	                    .any(|&word| tok.span.get_content(src).eq_ignore_ascii_case_str(word))
   280	        })
   281	    }
