   284	    /// or the token is in the list of words.
   285	    pub fn then_kind_any_or_words<F>(
   286	        self,
   287	        preds: &'static [F],
   288	        words: &'static [&'static str],
   289	    ) -> Self
   290	    where
   291	        F: Fn(&TokenKind) -> bool + Send + Sync + 'static,
   292	    {
   293	        self.then(move |tok: &Token, src: &[char]| {
   294	            preds.iter().any(|pred| pred(&tok.kind))
   295	                || words
   296	                    .iter()
   297	                    .any(|&word| tok.span.get_content(src).eq_ignore_ascii_case_str(word))
   298	        })
