   314	            preds_is.iter().any(|pred| pred(&tok.kind))
   315	                && !pred_not(&tok.kind)
   316	                && !ex
   317	                    .iter()
   318	                    .any(|&word| tok.span.get_content(src).eq_ignore_ascii_case_str(word))
   319	        })
