                    | "having"
                    | "do"
                    | "does"
                    | "did"
            );

            // Subject pronouns: I, you, we, they, he, she, it
            let is_subject_pronoun = matches!(
                word_lower.as_str(),
                "i" | "you" | "we" | "they" | "he" | "she" | "it"
            );

            // "to" (infinitive marker)
            let is_to = word_lower == "to";

            is_modal || is_auxiliary || is_subject_pronoun || is_to
        }
    } else {
        false
    };

    if preceded_by_verb_indicator {
        return true;
    }

    // Check if followed by a direct object (noun/pronoun) or "against"
    let followed_by_object = if let [ws, next_word, ..] = after {
        ws.kind.is_whitespace()
            && (next_word.kind.is_nominal()
                || next_word.kind.is_proper_noun()
                || next_word
                    .span
                    .get_content_string(source)
                    .to_lowercase()
                    == "against")
    } else {
        false
    };

    followed_by_object
}

/// Check if the word is "versed" preceded by "well" (as in "well-versed")
fn is_well_versed(before: &[Token], source: &[char], current_word: &str) -> bool {
    if current_word.to_lowercase() != "versed" {
        return false;
    }

    if let [.., prev_word, ws] = before {
        if ws.kind.is_whitespace() {
            let word_text = prev_word.span.get_content_string(source);
            let word_lower = word_text.to_lowercase();
            return matches!(word_lower.as_str(), "well" | "poorly" | "badly" | "better");
        }
    }
    false
}

/// Check if the word appears as a noun (preceded by article, adjective, or preposition)
fn is_noun_usage(before: &[Token], source: &[char]) -> bool {
    if before.len() < 2 {
        return false;
    }

    if let [.., prev_word, ws] = before {
        if !ws.kind.is_whitespace() {
            return false;
        }

        let word_text = prev_word.span.get_content_string(source);
        let word_lower = word_text.to_lowercase();

        // Articles: a, an, the
        if matches!(word_lower.as_str(), "a" | "an" | "the") {
            return true;
        }

        // Prepositions
        if matches!(
            word_lower.as_str(),
            "in" | "of"
                | "with"
                | "from"
                | "about"
                | "into"
                | "through"
                | "during"
                | "before"
                | "after"
                | "above"
                | "below"
                | "between"
                | "under"
        ) {
            return true;
        }

        // Numerals/quantifiers
        if matches!(
            word_lower.as_str(),
            "one" | "two"
                | "three"
                | "four"
                | "five"
                | "six"
                | "seven"
                | "eight"
                | "nine"
                | "ten"
                | "many"
                | "some"
                | "several"
                | "few"
                | "these"
                | "those"
        ) {
            return true;
        }

        // Possessives: my, your, his, her, its, our, their
        if matches!(
            word_lower.as_str(),
            "my" | "your" | "his" | "her" | "its" | "our" | "their"
        ) {
            return true;
        }
    }

    false
}

impl ExprLinter for VerseAsVerb {
    type Unit = Chunk;

    fn expr(&self) -> &dyn Expr {
        self.expr.as_ref()
    }

    fn match_to_lint_with_context(
        &self,
        matched_tokens: &[Token],
        source: &[char],
        context: Option<(&[Token], &[Token])>,
    ) -> Option<Lint> {
        let verse_tok = matched_tokens.first()?;
        let verse_text = verse_tok.span.get_content_string(source);
        let verse_lower = verse_text.to_lowercase();

        let Some((before, after)) = context else {
            return None;
        };

        // Don't flag "well versed", "poorly versed", etc.
        if is_well_versed(before, source, &verse_lower) {
            return None;
        }

        // Don't flag clear noun usage
        if is_noun_usage(before, source) {
            return None;
        }

        // Check for verb usage indicators
        if !is_verb_usage(before, after, source) {
            return None;
        }

        // Map the verse form to its replacement
        let replacement = match verse_lower.as_str() {
            "verse" => "face",
            "verses" => "faces",
            "versed" => "faced",
            "versing" => "facing",
            _ => return None,
        };

        Some(Lint {
            span: verse_tok.span,
            lint_kind: LintKind::WordChoice,
            suggestions: vec![
                Suggestion::replace_with_match_case(
                    replacement.chars().collect(),
                    verse_tok.span.get_content(source),
                ),
                Suggestion::replace_with_match_case(
                    "play against".chars().collect(),
                    verse_tok.span.get_content(source),
                ),
            ],
            message: format!(
                "`{verse_text}` is not a verb. Did you mean `{replacement}` or `play against`?"
            ),
            priority: 63,
        })
    }

    fn description(&self) -> &'static str {
        "Detects 'verse' and its inflections used incorrectly as a verb meaning 'compete against'."
    }
}

#[cfg(test)]
mod tests {
    use super::VerseAsVerb;
    use crate::linting::tests::{assert_lint_count, assert_no_lints, assert_suggestion_result};

    #[test]
    fn flags_will_verse() {
        assert_suggestion_result(
            "I will verse the computer.",
            VerseAsVerb::default(),
            "I will face the computer.",
