    fn default() -> Self {
        let targets = Lrc::new(WordSet::new(&[
            "verse", "verses", "versed", "versing", "vs",
        ]));
        Self {
            expr: Box::new(SequenceExpr::with(targets)),
        }
    }
}

/// Heuristic to determine if a word is being used as a verb based on surrounding context.
fn is_verb_usage(before: &[Token], after: &[Token], source: &[char]) -> bool {
    // Check preceding context for verb indicators
    let preceded_by_verb_indicator = if let [.., prev_word, ws] = before {
        ws.kind.is_whitespace() && {
            let word_text = prev_word.span.get_content_string(source);
            let word_lower = word_text.to_lowercase();

            // Modal verbs: can, could, will, would, shall, should, may, might, must
            let is_modal = matches!(
                word_lower.as_str(),
                "can" | "can't"
                    | "cannot"
                    | "could"
                    | "couldn't"
                    | "will"
                    | "won't"
                    | "would"
                    | "wouldn't"
                    | "shall"
                    | "shan't"
                    | "should"
                    | "shouldn't"
                    | "may"
                    | "might"
                    | "mightn't"
                    | "must"
                    | "mustn't"
            );

            // Auxiliary verbs: am, is, are, was, were, be, been, being, have, has, had, having
            let is_auxiliary = matches!(
                word_lower.as_str(),
                "am" | "is"
                    | "are"
                    | "was"
                    | "were"
                    | "be"
                    | "been"
                    | "being"
                    | "have"
                    | "has"
                    | "had"
                    | "having"
                    | "do"
                    | "does"
                    | "did"
            );

            // Subject pronouns: I, you, we, they, he, she, it
            let is_subject_pronoun = matches!(
                word_lower.as_str(),
                "i" | "you" | "we" | "they" | "he" | "she" | "it"
            );

            // "to" (infinitive marker)
            let is_to = word_lower == "to";

            is_modal || is_auxiliary || is_subject_pronoun || is_to
        }
    } else {
        false
    };

    if preceded_by_verb_indicator {
        return true;
    }

    // Check if followed by a direct object (noun/pronoun) or "against"
    let followed_by_object = if let [ws, next_word, ..] = after {
        ws.kind.is_whitespace()
            && (next_word.kind.is_nominal()
                || next_word.kind.is_proper_noun()
                || next_word
                    .span
                    .get_content_string(source)
                    .to_lowercase()
                    == "against")
    } else {
        false
    };

    followed_by_object
